class Solution {
public:
    int sumOfTheDigitsOfHarshadNumber(int x) {
        int sum = 0;
        while (x) {
            sum += x % 10;
            x /= 10;
        }
        if (x % sum == 0) {
            return sum;
        } else {
            return -1;
        }
    }
};
```
